custom_css:
/* Hacker Terminal Light Theme - Custom CSS */

/* Import monospace terminal fonts */
@import url('https://fonts.googleapis.com/css2?family=Fira+Code:wght@400;500&family=JetBrains+Mono:wght@400;500&display=swap');

/* Apply terminal font to text elements only - NOT icons */
body, .mes_text, input, textarea, select, button,
p, span:not([class*="fa"]), div, h1, h2, h3, h4, h5, h6, label, a {
  font-family: 'Fira Code', 'JetBrains Mono', 'Consolas', 'Monaco', monospace !important;
}

/* Preserve Font Awesome icons */
.fa, .fas, .far, .fal, .fab, .fa-solid, .fa-regular, .fa-light, .fa-brands,
[class^="fa-"], [class*=" fa-"] {
  font-family: 'Font Awesome 6 Free', 'Font Awesome 6 Brands' !important;
}

/* Subtle scanline effect for light mode */
body::before {
  content: "";
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  background: repeating-linear-gradient(
    0deg,
    rgba(100, 160, 100, 0.03),
    rgba(100, 160, 100, 0.03) 1px,
    transparent 1px,
    transparent 2px
  );
  z-index: 9999;
}

/* Terminal-style message formatting */
.mes_text {
  line-height: 1.4 !important;
  letter-spacing: 0.5px !important;
}

/* Sharp corners for terminal look */
.mes {
  margin-bottom: 8px !important;
  border-radius: 0 !important;
  border: 1px solid rgba(100, 160, 100, 0.3) !important;
  border-left: 3px solid rgba(100, 160, 100, 0.6) !important;
}

/* Focus effect for light mode */
input:focus, textarea:focus {
  box-shadow: 0 0 8px rgba(100, 160, 100, 0.5) !important;
  border-color: rgba(80, 140, 80, 0.8) !important;
  animation: terminal-glow-light 1s ease-in-out infinite alternate !important;
}

@keyframes terminal-glow-light {
  from { box-shadow: 0 0 5px rgba(100, 160, 100, 0.3); }
  to { box-shadow: 0 0 12px rgba(100, 160, 100, 0.6); }
}

/* Muted green scrollbar on light background */
::-webkit-scrollbar {
  width: 8px !important;
  background: rgba(245, 248, 245, 0.9) !important;
}
::-webkit-scrollbar-thumb {
  background: rgba(100, 160, 100, 0.4) !important;
  border: 1px solid rgba(100, 160, 100, 0.2) !important;
}
::-webkit-scrollbar-thumb:hover {
  background: rgba(100, 160, 100, 0.6) !important;
}

/* Green hover on buttons */
.menu_button:hover, .fa-solid:hover {
  color: rgba(70, 130, 70, 1) !important;
}

/* Subtle text shadow instead of glow */
.mes_text {
  text-shadow: 0 1px 1px rgba(100, 160, 100, 0.1) !important;
}

/* No animations for focus */
body, body * {
  transition-duration: 0s !important;
}

/* Top bar icons - dark color for light background */
.drawer-icon,
.drawer-icon.fa-solid,
#top-settings-holder .drawer-icon {
  color: rgba(60, 80, 60, 1) !important;
  text-shadow: none !important;
  filter: none !important;
  display: inline-flex;
  z-index: 9000 !important;
}
.drawer-icon.closedIcon,
.drawer-icon.closedIcon.fa-solid {
  color: rgba(60, 80, 60, 1) !important;
  opacity: 0.5 !important;
}
.drawer-icon.openIcon,
.drawer-icon.openIcon.fa-solid {
  color: rgba(60, 80, 60, 1) !important;
  opacity: 1 !important;
}
.drawer-icon:hover {
  color: rgba(80, 140, 80, 1) !important;
  opacity: 1 !important;
}
